import{_ as a,c as n,a1 as i,o as c}from"./chunks/framework.BDxlaA_J.js";const p=JSON.parse('{"title":"Footprinting sử dụng Maltego","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/2-Maltego-Basics.md","filePath":"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/2-Maltego-Basics.md"}'),h={name:"vi/categories/ethical-hacking-labs/1-footprinting-and-reconnaissance/2-Maltego-Basics.md"};function e(o,t,r,l,g,s){return c(),n("div",null,t[0]||(t[0]=[i('<h1 id="footprinting-su-dung-maltego" tabindex="-1">Footprinting sử dụng Maltego <a class="header-anchor" href="#footprinting-su-dung-maltego" aria-label="Permalink to &quot;Footprinting sử dụng Maltego&quot;">​</a></h1><p>Maltego là một ứng dụng tình báo mã nguồn mở và pháp y kỹ thuật số. Nó thu thập thông tin về mục tiêu và trình bày ở định dạng dễ hiểu.</p><h3 id="yeu-cau" tabindex="-1">Yêu cầu: <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu:&quot;">​</a></h3><ul><li>Máy ảo Kali Linux</li></ul><h3 id="muc-tieu" tabindex="-1">Mục tiêu: <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu:&quot;">​</a></h3><ul><li>Xác định địa chỉ IP</li><li>Xác định Domain và Schema tên miền</li><li>Xác định công nghệ phía Server</li><li>Xác định thông tin Service Oriented Architecture (SOA)</li><li>Xác định Name Server</li><li>Xác định Mail Exchanger</li><li>Xác định vị trí địa lý</li><li>Xác định các thực thể</li><li>Khám phá địa chỉ Email và số điện thoại</li></ul><p>Hiện tại có ba phiên bản của Maltego client: Maltego CE, Maltego Classic và Maltego XL. <strong>Hướng dẫn này sẽ tập trung vào Maltego Community Edition (CE).</strong></p><p>Kali Linux đi kèm với Maltego đã được cài đặt. Khởi chạy Maltego từ thanh ứng dụng. Nếu đây là lần đầu tiên bạn sử dụng Maltego, chỉ cần chọn phiên bản Maltego CE (Free) và tạo tài khoản miễn phí tại <a href="https://www.paterva.com/community/community.php" target="_blank" rel="noreferrer">https://www.paterva.com/community/community.php</a></p><h2 id="cac-thao-tac-co-ban-voi-maltego" tabindex="-1">Các thao tác cơ bản với Maltego <a class="header-anchor" href="#cac-thao-tac-co-ban-voi-maltego" aria-label="Permalink to &quot;Các thao tác cơ bản với Maltego&quot;">​</a></h2><ol><li>Nhấp vào biểu tượng (+) ở góc trên bên trái của GUI (trong thanh công cụ) để tạo cửa sổ graph mới (giống như một tài liệu trống).</li><li>Đi đến panel bên trái và mở rộng node <strong>Infrastructure</strong> dưới Entity Palette. Danh sách này có nhiều thực thể hữu ích như AS, DNS Name, Domain, MX Record, v.v.</li></ol><p><img src="https://s3-eu-central-1.amazonaws.com/euc-cdn.freshdesk.com/data/helpdesk/attachments/production/2015007002780/original/tJmLPIhee9OzhB4xqVKx1pT2NGixIRpdFg.jpg?1545115008" alt="alt text" title="Entity Palette - Maltego"></p><ol start="3"><li>Kéo thực thể Website vào phần New Graph(1) của bạn.</li><li>Đổi tên miền thành www.certifiedhacker.com</li></ol><h2 id="xac-đinh-cong-nghe-phia-server" tabindex="-1">Xác định công nghệ phía server <a class="header-anchor" href="#xac-đinh-cong-nghe-phia-server" aria-label="Permalink to &quot;Xác định công nghệ phía server&quot;">​</a></h2><ol start="5"><li>Nhấp chuột phải vào thực thể và chọn <strong>All Transforms</strong> rồi nhấp <strong>To Server Technologies [BuiltWith]</strong></li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-server-side-0.png" alt="alt text" title="Server Side Technologies"></p><p>Lưu ý: Maltego có thể hữu ích để hiển thị kết quả theo cách năng động hơn bằng cách trực quan hóa các liên kết liên kết giữa các mục tìm kiếm.</p><h2 id="xac-đinh-domain" tabindex="-1">Xác định Domain <a class="header-anchor" href="#xac-đinh-domain" aria-label="Permalink to &quot;Xác định Domain&quot;">​</a></h2><ol start="6"><li>Tạo graph mới hoặc xóa/lưu kết quả trước đó.</li><li>Nhấp chuột phải vào thực thể Domain và chọn <strong>All Transforms -&gt; To Domains [DNS]</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/dd19c689c25ad5a9f86d5c4450b26bb5f82eadc9/maltego-DNS-names.png" alt="alt text" title="DNS Names"></p><p>Transform này sẽ cố gắng kiểm tra schema tên miền với một tên miền và cố gắng xác định schema tên cụ thể cho tên miền đó.</p><h2 id="xac-đinh-thong-tin-soa" tabindex="-1">Xác định thông tin SOA <a class="header-anchor" href="#xac-đinh-thong-tin-soa" aria-label="Permalink to &quot;Xác định thông tin SOA&quot;">​</a></h2><ol start="8"><li>Tạo graph mới hoặc xóa/lưu kết quả trước đó.</li><li>Nhấp chuột phải vào thực thể Domain và chọn <strong>All Transforms -&gt; To DNS Name - SOA (Start of Authority)</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-DNS-SOA-2.png" alt="alt text" title="DNS Name - SOA"></p><h2 id="xac-đinh-mail-exchanger" tabindex="-1">Xác định Mail Exchanger <a class="header-anchor" href="#xac-đinh-mail-exchanger" aria-label="Permalink to &quot;Xác định Mail Exchanger&quot;">​</a></h2><ol start="10"><li>Tạo graph mới hoặc xóa/lưu kết quả trước đó.</li><li>Nhấp chuột phải vào thực thể Domain và chọn <strong>All Transforms -&gt; To DNS Name - MX (mail server)</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-MX-NameServers-3.png" alt="alt text" title="DNS MX Server"></p><h2 id="xac-đinh-name-server" tabindex="-1">Xác định Name Server <a class="header-anchor" href="#xac-đinh-name-server" aria-label="Permalink to &quot;Xác định Name Server&quot;">​</a></h2><ol start="12"><li>Tạo graph mới hoặc xóa/lưu kết quả trước đó.</li><li>Nhấp chuột phải vào thực thể Domain và chọn <strong>All Transforms -&gt; To DNS Name - NS (name server)</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-DNS-Name-Servers-4.png" alt="alt text" title="NS"></p><h2 id="xac-đinh-đia-chi-ip-vi-tri-va-whois" tabindex="-1">Xác định địa chỉ IP, Vị trí và Whois <a class="header-anchor" href="#xac-đinh-đia-chi-ip-vi-tri-va-whois" aria-label="Permalink to &quot;Xác định địa chỉ IP, Vị trí và Whois&quot;">​</a></h2><ol start="12"><li>Tạo graph mới hoặc xóa/lưu kết quả trước đó.</li><li>Nhấp chuột phải vào thực thể Website và chọn <strong>All Transforms -&gt; To IP address [DNS]</strong>.</li><li>Nhấp chuột phải vào thực thể IP và chọn <strong>All Transforms -&gt; To Location [city, country]</strong>.</li><li>Nhấp chuột phải vào thực thể Website và chọn <strong>All Transforms -&gt; To entities from whois [IBM Watson]</strong>.</li></ol><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/6fe1dc406ed480aea2acfb2e9f34d51a0536e042/maltego-WebSite-IP-Location-WhoisOnDomain-5.png" alt="alt text" title="IP Address, Location"></p><h2 id="tom-lai" tabindex="-1">Tóm lại: <a class="header-anchor" href="#tom-lai" aria-label="Permalink to &quot;Tóm lại:&quot;">​</a></h2><p>Maltego là một công cụ mạnh mẽ, bạn có thể trích xuất nhiều loại thông tin khác nhau qua mạng, công nghệ và nhân sự (email, số điện thoại, twitter).</p><p>Bằng cách trích xuất tất cả thông tin này, kẻ tấn công có thể thực hiện nhiều loại hoạt động恶意 khác nhau.</p><ul><li><p>Các công nghệ tích hợp sẵn của server: kẻ tấn công có thể tìm kiếm lỗ hổng liên quan đến bất kỳ công nghệ nào trong số đó và mô phỏng các kỹ thuật khai thác.</p></li><li><p>Thông tin SOA: cũng có thể hữu ích cho kẻ tấn công, họ có thể lợi dụng thông tin này để tìm lỗ hổng trong các dịch vụ và kiến trúc của nạn nhân và khai thác chúng.</p></li><li><p>Name Server: kẻ tấn công có thể khai thác NS bằng các kỹ thuật恶意 như DNS hijacking và chuyển hướng URL.</p></li><li><p>Địa chỉ IP: kẻ tấn công có thể lợi dụng địa chỉ IP bằng cách quét và tìm kiếm các cổng mở và lỗ hổng, từ đó cố gắng xâm nhập vào mạng và khai thác chúng.</p></li><li><p>Vị trí địa lý: kẻ tấn công có thể thực hiện các cuộc tấn công social engineering để khai thác thông tin nhạy cảm.</p></li></ul>',36)]))}const u=a(h,[["render",e]]);export{p as __pageData,u as default};
